-- Migration to add tier to zones and seed Chennai/Bangalore areas

-- 1. Add tier column to zones table
ALTER TABLE zones ADD COLUMN tier INTEGER;

-- 2. Define Helper for Inserting/Updating Zones
-- Note: Assuming UUIDs are generated by default or supplied. 
-- For seeding, we'll use a subquery to find the city_id.

-- CHENNAI TIER 1
ON CONFLICT (city_id, name) DO UPDATE SET tier = EXCLUDED.tier;

